/**
 * CLOUDFLARE QUERY FUNCTIONS
 * =========================
 * Optimized query functions powered by Cloudflare D1
 */

// Make these global so other scripts can access them
window.CLOUDFLARE_WORKER_URL = "https://robel-api.george-gamal139.workers.dev";
const CLOUDFLARE_WORKER_URL = window.CLOUDFLARE_WORKER_URL;

// Auth key for Cloudflare API
window.AUTH_KEY = "G792001";
const AUTH_KEY = window.AUTH_KEY;

// Helper to normalize IDs (e.g., 121 -> B121)
function normalizeId(id) {
    if (!id) return id;
    if (typeof id === 'number') id = id.toString();
    let clean = id.toString().trim().toUpperCase();
    if (/^\d+$/.test(clean)) return 'B' + clean;
    if (clean.startsWith('B')) return clean;
    return clean;
}
window.normalizeId = normalizeId;

// Global Cloudflare Fetcher with Smart Caching
async function fetchFromCloudflare(path, forceRefresh = false) {
    const cacheKey = `cf_cache_${path.replace(/[^a-z0-9]/gi, '_')}`;
    const cacheTTL = 1000 * 60 * 5; // 5 Minutes Cache for Guests (Fast updates)

    // Check if we have cached data (Bypass for Admins or Force Refresh)
    const isAdmin = window.location.pathname.includes('admin') ||
        document.getElementById('sys-cfg-2026') ||
        (window.currentUser && window.currentUser.role === 'admin') ||
        forceRefresh;

    if (!isAdmin) {
        try {
            const cached = localStorage.getItem(cacheKey);
            if (cached) {
                const { timestamp, data } = JSON.parse(cached);
                if (Date.now() - timestamp < cacheTTL) {
                    // console.log(`🚀 Loading ${path} from Smart Cache`);
                    return data;
                }
            }
        } catch (e) { }
    }

    try {
        // console.log(`🌐 Fetching ${path} from Cloudflare...`);
        const response = await fetch(`${CLOUDFLARE_WORKER_URL}/api/${path}`);
        if (response.ok) {
            const data = await response.json();

            // Transform data format if needed
            let processedData = data;

            const transformItem = (item) => ({
                // Priority: unit_id > building_id > project_id > id
                id: item.unit_id || item.building_id || item.project_id || item.id,

                // 🚀 COMPATIBILITY: Alias snake_case (D1) to camelCase (Frontend)
                buildingId: item.building_id || item.buildingId,
                projectId: item.project_id || item.projectId,
                project: item.project_id || item.projectId || item.project,
                code: item.code || item.unit_id,

                ...item,
                images: (typeof item.images === 'string' && item.images.startsWith('[')) ? JSON.parse(item.images) : item.images,
                image: (typeof item.image === 'string' && item.image.startsWith('[')) ? JSON.parse(item.image) : item.image
            });

            if (Array.isArray(data)) {
                processedData = data.map(transformItem);
            } else if (data && typeof data === 'object') {
                processedData = transformItem(data);
            }

            // Save to Cache
            try {
                localStorage.setItem(cacheKey, JSON.stringify({
                    timestamp: Date.now(),
                    data: processedData
                }));
            } catch (e) {
                // console.warn("⚠️ Storage Full, cannot cache new data.");
            }

            return processedData;
        } else {
            console.warn(`⚠️ API returned ${response.status}. Attempting cache fallback...`);
            const cached = localStorage.getItem(cacheKey);
            return cached ? JSON.parse(cached).data : null;
        }
    } catch (e) {
        console.error(`❌ Cloudflare Fetch Error:`, e);
        // CRITICAL FALLBACK: Use cache even if expired if network fails
        const cached = localStorage.getItem(cacheKey);
        if (cached) {
            // console.log("♻️ Network fail, using stale cache fallback.");
            return JSON.parse(cached).data;
        }
        return null;
    }
}

// ============================================================================
// PROJECT QUERIES
// ============================================================================

async function getAllProjects(forceRefresh = false) {
    try {
        let cfData = await fetchFromCloudflare('projects', forceRefresh);
        if (!cfData) return [];
        return cfData.map(p => ({
            ...p,
            id: normalizeId(p.id),
            name: (p.name && /^\d+$/.test(p.name)) ? 'B' + p.name : p.name
        }));
    } catch (error) {
        return [];
    }
}

async function getProject(projectId) {
    const normId = normalizeId(projectId);
    const projects = await getAllProjects();
    return projects.find(p => p.id === normId) || null;
}

async function getProjectsByStatus(status) {
    const projects = await getAllProjects();
    return projects.filter(p => p.status === status);
}

