// UNIT QUERIES
// ============================================================================

async function getAllUnits(forceRefresh = false) {
    // console.log(`🔍 Fetching units from Cloudflare (Force Refresh: ${forceRefresh})...`);
    const cfUnits = await fetchFromCloudflare('units', forceRefresh);
    if (!cfUnits) {
        console.warn("⚠️ Cloudflare fetch failed. Returning null to caller.");
        return null;
    }
    return cfUnits;
}

async function getUnitsByBuilding(buildingId, forceRefresh = false) {
    const normId = normalizeId(buildingId); // e.g. B133
    const rawId = normId.replace(/^B/i, ''); // e.g. 133

    // console.log(`🔍 [Query] Fetching building units: ${normId}`);

    try {
        let data = await fetchFromCloudflare(`units?buildingId=${encodeURIComponent(normId)}`, forceRefresh);
        if (!data || data.length === 0) {
            data = await fetchFromCloudflare(`units?building_id=${encodeURIComponent(normId)}`, forceRefresh);
        }

        // --- EMERGENCY FALLBACK FOR B133 --- 
        // If API fails and it's B133, look into window.inventory or projectMetadata
        if ((!data || data.length === 0) && (normId === 'B133' || rawId === '133')) {
            console.warn("🚨 API Failure for B133. Searching local inventory...");
            if (window.inventory && window.inventory.length > 0) {
                const local = window.inventory.filter(u => normalizeId(u.building_id || u.buildingId) === 'B133');
                if (local.length > 0) return local;
            }
        }

        return data || [];
    } catch (e) {
        console.error("Critical fetching error:", e);
        return [];
    }
}

async function getUnitsByProject(projectId) {
    // Try multiple parameter names as the API/DB might use different field names
    console.log(`🔍 Query API: Fetching project "${projectId}"`);

    // Try 1: projectId parameter
    let cfData = await fetchFromCloudflare(`units?projectId=${encodeURIComponent(projectId)}`);

    // Try 2: If empty, try 'project' parameter
    if (!cfData || cfData.length === 0) {
        console.log(`  ↳ Retry with 'project' param...`);
        cfData = await fetchFromCloudflare(`units?project=${encodeURIComponent(projectId)}`);
    }

    console.log(`  ✓ Found ${cfData ? cfData.length : 0} units`);
    return cfData || [];
}

async function getUnit(unitId, forceRefresh = false) {
    if (!unitId) return null;
    const normId = unitId.toString().trim();

    // 1. Try Memory first (window.inventory)
    if (window.inventory) {
        const found = window.inventory.find(u =>
            (u.unit_id && u.unit_id.toString() === normId) ||
            (u.code && u.code.toString() === normId) ||
            (u.id && u.id.toString() === normId)
        );
        if (found) return found;
    }

    // 2. Try direct fetch from Cloudflare (New Optimized Path)
    // Note: We'll implement this endpoint in the worker if it doesn't exist
    try {
        const cfData = await fetchFromCloudflare(`units?id=${encodeURIComponent(normId)}`, forceRefresh);
        if (cfData) {
            // Find in results (Cloudflare might return an array)
            const units = Array.isArray(cfData) ? cfData : [cfData];
            const found = units.find(u =>
                (u.unit_id && u.unit_id.toString() === normId) ||
                (u.code && u.code.toString() === normId) ||
                (u.id && u.id.toString() === normId)
            );
            if (found) return found;
        }
    } catch (e) {
        console.warn("Direct unit fetch failed, falling back to all units scan...");
    }

    // 3. Fallback: Search all units (Last resort, slow)
    const cfAll = await fetchFromCloudflare(`units`, forceRefresh);
    if (cfAll && Array.isArray(cfAll)) {
        return cfAll.find(u =>
            (u.unit_id && u.unit_id.toString() === normId) ||
            (u.code && u.code.toString() === normId) ||
            (u.id && u.id.toString() === normId)
        ) || null;
    }

    return null;
}

async function searchUnits(filters = {}) {
    let units = [];
    if (filters.projectId) {
        units = await getUnitsByProject(filters.projectId);
    } else if (filters.buildingId) {
        units = await getUnitsByBuilding(filters.buildingId);
    } else {
        units = await getAllUnits();
    }

    // Apply Client-Side Filters
    if (filters.status) units = units.filter(u => u.status === filters.status);
    if (filters.purpose) units = units.filter(u => u.purpose === filters.purpose || u.intent === filters.purpose);
    if (filters.minArea) units = units.filter(u => u.area >= filters.minArea);
    if (filters.maxArea) units = units.filter(u => u.area <= filters.maxArea);
    if (filters.minPrice) units = units.filter(u => (u.price || 0) >= filters.minPrice);
    if (filters.maxPrice) units = units.filter(u => (u.price || 0) <= filters.maxPrice);
    if (filters.floor) units = units.filter(u => u.floor == filters.floor);
    if (filters.view) units = units.filter(u => u.view === filters.view);

    if (filters.keyword) {
        const keyword = filters.keyword.toLowerCase();
        units = units.filter(u =>
            (u.unitNumber || '').toLowerCase().includes(keyword) ||
            (u.code || '').toLowerCase().includes(keyword) ||
            (u.view || '').toLowerCase().includes(keyword)
        );
    }
    return units;
}

async function getAvailableUnits(projectId) {
    const units = await getUnitsByProject(projectId);
    return units.filter(u => u.status === 'Available');
}

